mapper.select:
SELECT BRD_SEQ, BRD_TYPE, CATEGORY, IS_NOTICE, TITLE, VIEW_CNT, REG_DT FROM TB_BOARD WHERE DEL_YN = 'N' AND BRD_TYPE = #{brdType}
AND TITLE LIKE CONCAT('%', #{title}, '%')
ORDER BY IS_NOTICE DESC, BRD_SEQ DESC

mapper.update:
UPDATE TB_BOARD
SET VIEW_CNT = VIEW_CNT + 1
WHERE BRD_SEQ = #{brdSeq}

mapper.select:
SELECT * FROM TB_FILE
WHERE REF_TABLE = #{refTable}
  AND REF_SEQ = #{refSeq}
  AND DEL_YN = 'N'
ORDER BY FILE_SEQ ASC
